# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3

app = Flask(__name__)

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    try:
        data = request.json
        message = data['message']
        signature = data['signature']
        address_from_private_key = data.get('address_from_private_key')

        if not all([message, signature]):
            return jsonify({'error': 'Message and signature are required'}), 400

        w3 = Web3()
        recovered_address = w3.eth.account.recover(message, signature=signature)

        if address_from_private_key is None:
            if recovered_address != data.get('address'):
                return jsonify({'error': 'Invalid signature'}), 401
            else:
                return jsonify({'message': 'Authentication successful', 'authenticated_user': True}), 200

        elif Web3.toChecksumAddress(recovered_address) == address_from_private_key:
            return jsonify({'message': 'Authentication successful', 'authenticated_user': True}), 200
        else:
            return jsonify({'error': 'Invalid signature'}), 401

    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)